import React from 'react';
import { Routes, Route, Link } from 'react-router-dom';
import Home from './Home';
import Generate from './Generate';
import Decrypt from './Decrypt';
import './App.css';

function App() {
  return (
    <div className="container">
      <h1>Smart Secure QR</h1>
      {/* logo image - using placeholder; replace with your own graphic or put logo.png in public/ */}
      <img src="https://via.placeholder.com/120?text=QR" alt="logo" className="logo" />
      <nav>
        <Link to="/">Home</Link> | <Link to="/generate">Generate</Link> | <Link to="/decrypt">Decrypt</Link>
      </nav>
      <hr />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/generate" element={<Generate />} />
        <Route path="/decrypt" element={<Decrypt />} />
      </Routes>
    </div>
  );
}

export default App;
